# Write your MySQL query statement below
with t1 as ( select user_id, count(*)as cnt from MovieRating group by user_id ), t2 as ( select movie_id, avg(rating) as avg_rating from MovieRating where created_at >='2020-02-01' and created_at < '2020-03-01' group by movie_id), t3 as ( select title as results from Movies where movie_id in ( select movie_id from t2 where avg_rating = (select max(avg_rating) from t2) ) order by title limit 1) (select name as results from Users where user_id in ( select user_id from t1 where cnt = (select max(cnt) from t1) ) order by name asc limit 1) union all (select results from t3 order by results);